import{_ as t,o as e,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3680_家登/20260509/F17_籌碼分佈與法人動態分析.md","filePath":"審計報告庫/財務審計/3680_家登/20260509/F17_籌碼分佈與法人動態分析.md"}'),o={name:"審計報告庫/財務審計/3680_家登/20260509/F17_籌碼分佈與法人動態分析.md"};function l(n,a,s,h,d,c){return e(),i("div",null,[...a[0]||(a[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f17-籌碼分佈與法人動態分析-財務審計專家報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 - 財務審計專家報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-財務審計專家報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>外資、投信與自營商的買賣超動向，千張大戶持股變化分析。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：外資近 5 日累計淨買超 937 張，持股 72-78%。投信清淡。千張大戶 45.76%，散戶 64%。法人無明確共識，籌碼偏散。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：2026/5/8</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>外資 5 日買賣超：+769K→+360K→+203K→-433K→+39K，合計淨買超 937K 張。投信僅 2 日有交易（買超 31.5K/187K），態度消極。千張大戶 23 人 45.76%，散戶 14,882 戶佔 64%。籌碼呈外資主導、散戶跟隨結構，缺乏投信鎖碼超額動能。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、法人動態" tabindex="-1">一、法人動態 <a class="header-anchor" href="#一、法人動態" aria-label="Permalink to &quot;一、法人動態&quot;">​</a></h3><p>外資淨買超但 5/7 一度轉賣 43.3 萬顯示分歧加大。投信僅 2 日交易無布局意願，可能因高質押、負 FCF 等治理疑慮。外資買盤反映 2nm 題材與光罩盒獨佔地位。</p><h3 id="二、大戶與散戶結構" tabindex="-1">二、大戶與散戶結構 <a class="header-anchor" href="#二、大戶與散戶結構" aria-label="Permalink to &quot;二、大戶與散戶結構&quot;">​</a></h3><p>千張大戶 45.76% 但 400-1,000 張中實戶僅 22 人（18.25%），結構呈啞鈴型。上漲時大戶鎖碼有利，下跌時中實戶護盤力道不足，散戶 64% 增加波動性。</p><h3 id="三、籌碼動能" tabindex="-1">三、籌碼動能 <a class="header-anchor" href="#三、籌碼動能" aria-label="Permalink to &quot;三、籌碼動能&quot;">​</a></h3><p>外資持股 78% 再買超空間有限。真正潛在買盤來自投信——若 FCF 缺口收窄、毛利率止穩，投信布局將是股價向上催化劑。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析（Skepticism Mandate） <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析（Skepticism Mandate）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>法人無共識，外資買超動能遞減</strong>（77→4 萬股），投信零參與。若外資轉賣籌碼陷入買盤真空<strong>風險</strong>。</li><li><strong>散戶 64% 破碎化</strong>，股價震盪易非理性賣出造成超跌。</li><li><strong>投信缺席反映治理疑慮</strong>（高質押、負 FCF、三率同降），這對成長股是重要<strong>負面訊號</strong>。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>外資持股 78% 為長期資金</strong>，不易短線撤出。</li><li><strong>千張大戶 45.76% 鎖碼</strong>提供籌碼穩定度。</li><li><strong>若 2026 H1 營運持續強勁</strong>（Q1 +30.2%），投信可能回補形成新動能。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>籌碼由外資主導、投信缺席，散戶化增加波動。短期看 Q1 動能與外資進出，中長期需投信因基本面改善而進場。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>原始數據：FinMind TaiwanStockInstitutionalHolding（法人買賣超 2026/05/04-05/08）</li><li>原始數據：FinMind TaiwanStockShareholdingSpread（股權分散表 2026/05/08）</li><li>原始數據：FinMind TaiwanStockHolding（外資持股比）</li><li>查詢參數：stock_id=3680, date=2026-05-04 to 2026-05-08</li><li>數據查詢日期：2026-05-09</li></ul>',24)])])}const m=t(o,[["render",l]]);export{u as __pageData,m as default};
